bool ArgParser::Help() {
  for(int i = 0; i < arguments.size(); ++i) {
    if (arguments[i].help_requested) {
      return true;
    }
  }
  return false;
}

std::string ArgParser::HelpDescription() {
  std::stringstream help_string;
  help_string << name << "\n";
  for (const auto &arg : arguments) {
    if (arg.help_requested) {
      help_string << arg.help_message << "\n\n";
      continue;
    }
      help_string << (arg.short_name != 0 ? "-" : "") 
              << (arg.short_name != 0 ? std::string(1, arg.short_name) + ", " : "")
              << (arg.long_name.empty() ? "" : "--")
              << arg.long_name
              << ", <" << arg.argument_type << ">, " 
              << arg.help_message;


    if (arg.is_multi_value) {
      help_string << " [repeated";
      if (arg.min_arguments_count > 0) {
        help_string << ", min args = " << arg.min_arguments_count;
      }
      help_string << "]";
    }

    if (arg.is_default) {
      if(arg.argument_type == "string"){
        if (arg.is_default) {
          help_string << " [default = " << arg.value[0] << "]";
        }
      }else if(arg.argument_type == "int" && arg.is_default && !arg.value.empty()){
        help_string << " [default = " << arg.value[0] << "]";
      }else if(arg.argument_type == "bool"){
        if (arg.is_default) {
          help_string << " [default = " << (arg.value[0] == "1" ? "true" : "false") << "]";
        }
      }
    }
    help_string << "\n\n";
  }
  help_string << "\n\n" << (arguments[0].short_name != 0 ? "-" : "") 
            << (arguments[0].short_name != 0 ? std::string(1, arguments[0].short_name) + ", " : "")
            << "--help Display this help and exit\n";

  return help_string.str();
}



