перепиши структуры на наследования(никаких вируалов лямбдв функций std::function и тп) только дефолтные

Для того чтобы переписать структуры на наследование, нам нужно распределить общие атрибуты и функции в базовом классе аргумента, а затем создать отдельные производные классы для каждого типа аргументов. Ниже показан возможный способ организации наследования аргументов:

```cpp
namespace ArgumentParser {

class Argument {
public:
  enum class Type { String, Integer, Bool };

  std::string long_name;
  char short_name = 0;
  Type type;
  size_t min_arguments_count = 1;
  bool is_multi_value = false;
  bool is_positional = false;
  bool help_requested = false;
  std::string help_message;
  bool is_default = false;

  Argument(Type t) : type(t) {}
  virtual ~Argument() = default;
};

class StringArgument : public Argument {
public:
  std::vector<std::string> value;
  std::string* str_value_ptr = nullptr;

  StringArgument()
    : Argument(Type::String) {}
};

class IntArgument : public Argument {
public:
  std::vector<int32_t> value;
  std::vector<int32_t>* int_values_ptr = nullptr;

  IntArgument()
    : Argument(Type::Integer) {}
};

class BoolArgument : public Argument {
public:
  bool value = false;
  bool* bool_value_ptr = nullptr;

  BoolArgument()
    : Argument(Type::Bool) {}
};

class ArgParser {
public:
  // ... Остальные члены класса остались без изменений, за исключением того,
  // что вектор arguments теперь хранит указатели на объекты базового класса:
  std::vector<Argument*> arguments;

  // Деструктор был добавлен для правильного удаления аргументов
  ~ArgParser() {
    for (auto arg : arguments) {
      delete arg;
    }
  }

  // Изменения в функциях для работы с аргументами: добавление нового аргумента
  // теперь создает объект соответствующего производного класса
  ArgParser& AddStringArgument(std::string long_name) {
    StringArgument* new_argument = new StringArgument();
    new_argument->long_name = long_name;
    arguments.push_back(new_argument);
    return *this;
  }

  // Пример использования функции для работы с типами данных аргументов
  std::string GetStringValue(std::string long_name) {
    int32_t index_of_argument = FindByLongName(long_name);
    if (index_of_argument >= 0) {
      StringArgument* arg = dynamic_cast<StringArgument*>(arguments[index_of_argument]);
      return arg->value[0];
    }
    throw std::runtime_error("Argument not found or wrong type");
  }

  // ... Остальные функции будут иметь аналогичные изменения

  // ... Также необходимо обновить функции FindByLongName и FindByShortName,
  // чтобы они учитывали новую структуру класса ArgParser

};

} // namespace ArgumentParser
```

Последовательность наследования позволяет нам избежать дублирования общих атрибутов в классах аргументов. Каждый производный класс добавляет собственные атрибуты в соответствии с типом данных (строки, числа, булевы значения). Приведенный пример требует дальнейшей доработки и адаптации всех функций класса `ArgParser` к новой структуре данных. Функции, которые работают с аргументами, теперь должны использовать `dynamic_cast` для приведения базового указателя к нужному производному типу перед доступом к их членам-данным.

Обратите внимание, что реализация функций, таких как `GetStringValue`, теперь требует проверки, действительно ли указатель на аргумент может быть приведен к нужному производному типу, иначе должно быть выброшено исключение. Это необходимо, потому что `FindByLongName` может вернуть указатель на аргумент неправильного типа.

В дополнение, я добавил деструктор в класс `ArgParser` для удаления всех элементов из вектора `arguments` и освобождения занимаемой ими памяти при уничтожении объекта `ArgParser`.

Это довольно высокоуровневое представление, и вы можете расширить его в соответствии с требованиями вашего приложения.

